const body = $input.item.json.body;
const estados = {
  '1': 'Pago pendiente', '2': 'Pago aceptado', '3': 'En preparación',
  '4': 'Enviado', '5': 'Entregado', '6': 'Cancelado', '7': 'Reembolsado'
};
const nuevo = estados[String(body.new_status)] || `Estado ${body.new_status}`;
const anterior = estados[String(body.old_status)] || `Estado ${body.old_status}`;
return [{json: {
  order_id: body.order_id,
  reference: body.reference,
  email: body.customer_email || body.email,
  customer: body.customer,
  nuevo_estado: nuevo,
  anterior_estado: anterior,
  total: body.total
}}];
